def _build_nested_qualified_name(
    self,
    func_node: Node,
    module_qn: str,
    func_name: str,
    lang_config: LanguageSpec,
) -> str | None:
    path_parts: list[str] = []
    current = func_node.parent

    if not isinstance(current, Node):
        logger.warning(
            ls.CALL_UNEXPECTED_PARENT, node=func_node, parent_type=type(current)
        )
        return None

    while current and current.type not in lang_config.module_node_types:
        if current.type in lang_config.function_node_types:
            if name_node := current.child_by_field_name(cs.FIELD_NAME):
                text = name_node.text
                if text is not None:
                    path_parts.append(text.decode(cs.ENCODING_UTF8))
        elif current.type in lang_config.class_node_types:
            return None

        current = current.parent

    path_parts.reverse()
    if path_parts:
        return f"{module_qn}{cs.SEPARATOR_DOT}{cs.SEPARATOR_DOT.join(path_parts)}{cs.SEPARATOR_DOT}{func_name}"
    return f"{module_qn}{cs.SEPARATOR_DOT}{func_name}"

def _get_call_target_name(self, call_node: Node) -> str | None:
    if func_child := call_node.child_by_field_name(cs.TS_FIELD_FUNCTION):
        match func_child.type:
            case (
                cs.TS_IDENTIFIER
                | cs.TS_ATTRIBUTE
                | cs.TS_MEMBER_EXPRESSION
                | cs.CppNodeType.QUALIFIED_IDENTIFIER
                | cs.TS_SCOPED_IDENTIFIER
            ):
                if func_child.text is not None:
                    return str(func_child.text.decode(cs.ENCODING_UTF8))
            case cs.TS_CPP_FIELD_EXPRESSION:
                field_node = func_child.child_by_field_name(cs.FIELD_FIELD)
                if field_node and field_node.text:
                    return str(field_node.text.decode(cs.ENCODING_UTF8))
            case cs.TS_PARENTHESIZED_EXPRESSION:
                return self._get_iife_target_name(func_child)

    match call_node.type:
        case (
            cs.TS_CPP_BINARY_EXPRESSION
            | cs.TS_CPP_UNARY_EXPRESSION
            | cs.TS_CPP_UPDATE_EXPRESSION
        ):
            operator_node = call_node.child_by_field_name(cs.FIELD_OPERATOR)
            if operator_node and operator_node.text:
                operator_text = operator_node.text.decode(cs.ENCODING_UTF8)
                return cpp_utils.convert_operator_symbol_to_name(operator_text)
        case cs.TS_METHOD_INVOCATION:
            object_node = call_node.child_by_field_name(cs.FIELD_OBJECT)
            name_node = call_node.child_by_field_name(cs.FIELD_NAME)
            if name_node and name_node.text:
                method_name = str(name_node.text.decode(cs.ENCODING_UTF8))
                if not object_node or not object_node.text:
                    return method_name
                object_text = str(object_node.text.decode(cs.ENCODING_UTF8))
                return f"{object_text}{cs.SEPARATOR_DOT}{method_name}"

    if name_node := call_node.child_by_field_name(cs.FIELD_NAME):
        if name_node.text is not None:
            return str(name_node.text.decode(cs.ENCODING_UTF8))

    return None

def _get_node_name(self, node: Node, field: str = cs.FIELD_NAME) -> str | None:
    name_node = node.child_by_field_name(field)
    if not name_node:
        return None
    text = name_node.text
    return None if text is None else text.decode(cs.ENCODING_UTF8)

def _process_calls_in_functions(
    self,
    root_node: Node,
    module_qn: str,
    language: cs.SupportedLanguage,
    queries: dict[cs.SupportedLanguage, LanguageQueries],
    call_site_file_path: str,
) -> None:
    result = get_function_captures(root_node, language, queries)
    if not result:
        return

    lang_config, captures = result
    func_nodes = captures.get(cs.CAPTURE_FUNCTION, [])
    for func_node in func_nodes:
        if not isinstance(func_node, Node):
            continue
        if self._is_method(func_node, lang_config):
            continue

        if language == cs.SupportedLanguage.CPP:
            func_name = cpp_utils.extract_function_name(func_node)
        else:
            func_name = self._get_node_name(func_node)
        if not func_name:
            continue
        if func_qn := self._build_nested_qualified_name(
            func_node, module_qn, func_name, lang_config
        ):
            self._ingest_function_calls(
                func_node,
                func_qn,
                cs.NodeLabel.FUNCTION,
                module_qn,
                language,
                queries,
                call_site_file_path=call_site_file_path,
            )

def _is_method_chain(self, call_name: str) -> bool:
    if cs.CHAR_PAREN_OPEN not in call_name or cs.CHAR_PAREN_CLOSE not in call_name:
        return False
    parts = call_name.split(cs.SEPARATOR_DOT)
    method_calls = sum(
        cs.CHAR_PAREN_OPEN in part and cs.CHAR_PAREN_CLOSE in part for part in parts
    )
    return method_calls >= 1 and len(parts) >= 2

def resolve_builtin_call_with_provenance(
    self, call_name: str
) -> ResolveResult | None:
    return ResolveResult.from_tuple(
        self.resolve_builtin_call(call_name),
        RESOLVED_VIA_EXACT,
        CONFIDENCE_EXACT,
    )

def resolve_cpp_operator_call_with_provenance(
    self, call_name: str, module_qn: str
) -> ResolveResult | None:
    return ResolveResult.from_tuple(
        self.resolve_cpp_operator_call(call_name, module_qn),
        RESOLVED_VIA_EXACT,
        CONFIDENCE_EXACT,
    )

def resolve_function_call_with_provenance(
    self,
    call_name: str,
    module_qn: str,
    local_var_types: dict[str, str] | None = None,
    class_context: str | None = None,
) -> ResolveResult | None:
    if result := self._try_resolve_iife(call_name, module_qn):
        return ResolveResult.from_tuple(
            result, RESOLVED_VIA_EXACT, CONFIDENCE_EXACT
        )

    if self._is_super_call(call_name):
        return ResolveResult.from_tuple(
            self._resolve_super_call(call_name, class_context),
            RESOLVED_VIA_EXACT,
            CONFIDENCE_EXACT,
        )

    if cs.SEPARATOR_DOT in call_name and self._is_method_chain(call_name):
        # Chained calls (``a.b().c()``) infer types one link at a
        # time — each hop is a guess.  Tag as heuristic so downstream
        # filters can deprioritize relative to a direct binding.
        return ResolveResult.from_tuple(
            self._resolve_chained_call(call_name, module_qn, local_var_types),
            RESOLVED_VIA_HEURISTIC,
            CONFIDENCE_HEURISTIC,
        )

    if tagged := self._try_resolve_via_imports_tagged(
        call_name, module_qn, local_var_types
    ):
        return tagged

    if result := self._try_resolve_same_module(call_name, module_qn):
        return ResolveResult.from_tuple(
            result, RESOLVED_VIA_EXACT, CONFIDENCE_EXACT
        )

    # Trie fallback — the resolver couldn't bind via any strict path
    # and is falling back to a registry suffix search, picking the
    # candidate with the smallest import distance.  This is the
    # textbook "name matched within scope but ambiguity existed"
    # case from the ticket spec → heuristic / 0.6.
    return ResolveResult.from_tuple(
        self._try_resolve_via_trie(call_name, module_qn),
        RESOLVED_VIA_HEURISTIC,
        CONFIDENCE_HEURISTIC,
    )

def resolve_java_method_call_with_provenance(
    self,
    call_node: Node,
    module_qn: str,
    local_var_types: dict[str, str],
) -> ResolveResult | None:
    return ResolveResult.from_tuple(
        self.resolve_java_method_call(call_node, module_qn, local_var_types),
        RESOLVED_VIA_EXACT,
        CONFIDENCE_EXACT,
    )

def _extract_name_from_function_definition(func_node: Node) -> str | None:
    def find_function_declarator(node: Node) -> str | None:
        if node.type == cs.CppNodeType.FUNCTION_DECLARATOR:
            return extract_function_name(node)

        for child in node.children:
            if child.type in (
                cs.CppNodeType.POINTER_DECLARATOR,
                cs.CppNodeType.REFERENCE_DECLARATOR,
                cs.CppNodeType.FUNCTION_DECLARATOR,
            ):
                result = find_function_declarator(child)
                if result:
                    return result
        return None

    return find_function_declarator(func_node)

def build_qualified_name(node: Node, module_qn: str, name: str) -> str:
    module_parts = module_qn.split(cs.SEPARATOR_DOT)

    is_module_file = len(module_parts) >= 3 and (
        bool(cs.CPP_MODULE_PATH_MARKERS & set(module_parts))
        or any(part.endswith(cs.CPP_MODULE_EXTENSIONS) for part in module_parts)
    )

    if is_module_file:
        project_name = module_parts[0]
        filename = module_parts[-1]

        return cs.SEPARATOR_DOT.join([project_name, filename, name])

    path_parts: list[str] = []
    current = node.parent

    while current and current.type != cs.CppNodeType.TRANSLATION_UNIT:
        if current.type == cs.CppNodeType.NAMESPACE_DEFINITION:
            namespace_name = None
            name_node = current.child_by_field_name(cs.KEY_NAME)
            if name_node and name_node.text:
                namespace_name = safe_decode_text(name_node)
            else:
                for child in current.children:
                    if (
                        child.type
                        in (
                            cs.CppNodeType.NAMESPACE_IDENTIFIER,
                            cs.CppNodeType.IDENTIFIER,
                        )
                        and child.text
                    ):
                        namespace_name = safe_decode_text(child)
                        break
            if namespace_name:
                path_parts.append(namespace_name)
        current = current.parent

    path_parts.reverse()

    if path_parts:
        return cs.SEPARATOR_DOT.join([module_qn, *path_parts, name])
    return cs.SEPARATOR_DOT.join([module_qn, name])

def extract_function_name(func_node: Node) -> str | None:
    match func_node.type:
        case (
            cs.CppNodeType.FUNCTION_DEFINITION
            | cs.CppNodeType.CONSTRUCTOR_OR_DESTRUCTOR_DEFINITION
            | cs.CppNodeType.INLINE_METHOD_DEFINITION
            | cs.CppNodeType.OPERATOR_CAST_DEFINITION
        ):
            return _extract_name_from_function_definition(func_node)
        case (
            cs.CppNodeType.DECLARATION
            | cs.CppNodeType.CONSTRUCTOR_OR_DESTRUCTOR_DECLARATION
        ):
            return _extract_name_from_declaration(func_node)
        case cs.CppNodeType.FIELD_DECLARATION:
            name = _extract_name_from_declaration(func_node)
            return name or _extract_name_from_field_declaration(func_node)
        case cs.CppNodeType.FUNCTION_DECLARATOR:
            return _extract_name_from_function_declarator(func_node)
        case cs.CppNodeType.TEMPLATE_DECLARATION:
            return _extract_name_from_template_declaration(func_node)
        case _:
            return None

def is_exported(node: Node) -> bool:
    current = node
    while current and current.parent:
        parent = current.parent
        found_export = False

        for child in parent.children:
            if child == current:
                break
            if child.text:
                child_text = safe_decode_text(child)
                if child_text == cs.CppNodeType.EXPORT and child.type in (
                    cs.CppNodeType.EXPORT,
                    cs.CppNodeType.EXPORT_KEYWORD,
                    cs.CppNodeType.IDENTIFIER,
                    cs.CppNodeType.PRIMITIVE_TYPE,
                ):
                    found_export = True

        if found_export:
            return True

        if current.type in (
            cs.CppNodeType.DECLARATION,
            cs.CppNodeType.FUNCTION_DEFINITION,
            cs.CppNodeType.TEMPLATE_DECLARATION,
            cs.CppNodeType.CLASS_SPECIFIER,
            cs.CppNodeType.TRANSLATION_UNIT,
        ):
            break
        current = current.parent

    return False

